# app/mailers/application_mailer.rb
class ApplicationMailer < ActionMailer::Base
  default from: ENV['SENDGRID_FROM_EMAIL'] || 'noreply@example.com'
  layout 'mailer'
end

# app/mailers/user_mailer.rb
class UserMailer < ApplicationMailer
  def welcome_email(user)
    @user = user
    @url = root_url
    
    mail(
      to: email_address_with_name(user.email, user.name),
      subject: 'Welcome to Our Application',
      reply_to: ENV['SENDGRID_REPLY_TO_EMAIL']
    )
  end

  def notification_email(user, notification)
    @user = user
    @notification = notification
    
    mail(
      to: user.email,
      subject: notification.subject,
      cc: notification.cc_emails,
      bcc: notification.bcc_emails,
      reply_to: ENV['SENDGRID_REPLY_TO_EMAIL']
    )
  end

  def password_reset(user, token)
    @user = user
    @token = token
    @reset_url = edit_password_reset_url(token: @token)
    
    mail(
      to: user.email,
      subject: 'Password Reset Instructions'
    )
  end

  def bulk_email(users, subject, content)
    @content = content
    
    users.each do |user|
      @user = user
      mail(
        to: user.email,
        subject: subject
      ).deliver_later
    end
  end

  def email_with_attachment(user, attachment_data)
    @user = user
    
    attachments[attachment_data[:filename]] = {
      mime_type: attachment_data[:mime_type],
      content: attachment_data[:content]
    }
    
    mail(
      to: user.email,
      subject: 'Your Requested Document'
    )
  end

  def custom_headers_email(user, custom_data)
    @user = user
    @custom_data = custom_data
    
    headers['X-Custom-Header'] = custom_data[:header_value]
    headers['X-Priority'] = '1'
    
    mail(
      to: user.email,
      subject: custom_data[:subject]
    )
  end
end

