# lib/sendgrid_delivery_method.rb
class SendgridDeliveryMethod
  attr_accessor :settings

  def initialize(settings)
    @settings = settings
  end

  def deliver!(mail)
    require 'net/smtp'
    
    smtp = Net::SMTP.new(settings[:address], settings[:port])
    smtp.enable_starttls_auto if settings[:enable_starttls_auto]
    
    smtp.start(settings[:domain], settings[:user_name], settings[:password], settings[:authentication]) do |smtp_connection|
      smtp_connection.send_message(mail.encoded, mail.from.first, mail.destinations)
    end
  end
end

# config/initializers/sendgrid.rb
if Rails.env.development? || Rails.env.production?
  ActionMailer::Base.add_delivery_method :sendgrid, SendgridDeliveryMethod
end